const ts = String(Date.now());
const suffix = ts.slice(-6);
const customer = '91' + String(Date.now() + 11111).slice(-10);
const empty = '91' + String(Date.now() + 22222).slice(-10);
const cancel = '91' + String(Date.now() + 33333).slice(-10);
const owner = '91' + String(Date.now() + 44444).slice(-10);
return [{
  json: {
    owner_chat_id: owner,
    customer_chat_id: customer,
    empty_chat_id: empty,
    cancel_chat_id: cancel,
    address: '221 Test Street, Bengaluru',
    milk_name: 'Linked Proof Milk 500ml ' + suffix,
    milk_sku: 'LINKPROOFMILK' + suffix,
    atta_name: 'Linked Proof Atta 5kg ' + suffix,
    atta_sku: 'LINKPROOFATTA' + suffix,
    milk_initial_price: 52,
    milk_initial_stock: 9,
    atta_initial_price: 310,
    atta_initial_stock: 3,
    updated_milk_price: 55,
    low_stock: 1,
    replenished_stock: 5,
    order_qty: 2,
    expected_line_total: 110,
    test_mode: true,
    run_token: 'linked_' + suffix,
  }
}];

const seed = $('Seed Linked Inputs').first().json || {};
const seededRows = $('Seed Proof Inventory').all().map((item) => item.json || {});
const browse = $('Run Browse').first().json || {};
const emptyPlace = $('Run Empty Place').first().json || {};
const emptyConfirm = $('Run Empty Confirm').first().json || {};
const lowStockDb = $('Set Low Stock').first().json || {};
const insufficientAdd = $('Run Insufficient Add').first().json || {};
const failedCart = $('Verify Failed Cart').first().json || {};
const updatedItem = $('Set Updated Item').first().json || {};
const add = $('Run Customer Add').first().json || {};
const view = $('Run View Cart').first().json || {};
const cart = $('Verify Cart DB').first().json || {};
const place = $('Run Place Order').first().json || {};
const pending = $('Verify Pending Order').first().json || {};
const confirm = $('Run Confirm Order').first().json || {};
const confirmRows = $('Verify After Confirm DB').all().map((item) => item.json || {});
const trackConfirm = $('Run Track Confirm').first().json || {};
const accept = $('Run Owner Accept').first().json || {};
const acceptDb = $('Verify Accept Status').first().json || {};
const trackAccept = $('Run Track Accept').first().json || {};
const dispatch = $('Run Owner Dispatch').first().json || {};
const dispatchDb = $('Verify Dispatch Status').first().json || {};
const trackDispatch = $('Run Track Dispatch').first().json || {};
const delivered = $('Run Owner Delivered').first().json || {};
const deliveredDb = $('Verify Delivered Status').first().json || {};
const trackDelivered = $('Run Track Delivered').first().json || {};
const cancelAdd = $('Run Cancel Add').first().json || {};
const cancelPlace = $('Run Cancel Place').first().json || {};
const cancelOrder = $('Run Cancel Order').first().json || {};
const cancelDbRows = $('Verify Cancel DB').all().map((item) => item.json || {});

const byKind = (rows, kind) => rows.find((row) => String(row.kind || '') === kind) || {};
const bySku = (rows, sku) => rows.find((row) => String(row.sku || '') === String(sku || '')) || {};
const hasButton = (resp, id) => Array.isArray(resp.buttons) && resp.buttons.some((button) => String(button.id || '') === id);
const hasButtonPrefix = (resp, prefix) => Array.isArray(resp.buttons) && resp.buttons.some((button) => String(button.id || '').startsWith(prefix));
const hasListRow = (resp, id) => Array.isArray(resp.list_sections) && resp.list_sections.some((section) => Array.isArray(section.rows) && section.rows.some((row) => String(row.id || '') === id));
const bodyText = (resp) => String(resp.body_text || resp.confirmation_message || '');
const seededMilk = bySku(seededRows, seed.milk_sku);
const seededAtta = bySku(seededRows, seed.atta_sku);

return [{
  json: {
    owner_chat_id: seed.owner_chat_id,
    customer_chat_id: seed.customer_chat_id,
    empty_chat_id: seed.empty_chat_id,
    cancel_chat_id: seed.cancel_chat_id,
    order_id: String(place.order_id || ''),
    responses: {
      empty_place: bodyText(emptyPlace),
      empty_confirm: bodyText(emptyConfirm),
      browse: bodyText(browse),
      insufficient_add: bodyText(insufficientAdd),
      add: bodyText(add),
      view: bodyText(view),
      place: bodyText(place),
      confirm: bodyText(confirm),
      track_confirm: bodyText(trackConfirm),
      owner_accept: bodyText(accept),
      track_accept: bodyText(trackAccept),
      owner_dispatch: bodyText(dispatch),
      track_dispatch: bodyText(trackDispatch),
      owner_delivered: bodyText(delivered),
      track_delivered: bodyText(trackDelivered),
      cancel_add: bodyText(cancelAdd),
      cancel_place: bodyText(cancelPlace),
      cancel_order: bodyText(cancelOrder),
    },
    evidence: {
      seeded_inventory: seededRows,
      browse_rows: Array.isArray(browse.list_sections) ? browse.list_sections : [],
      low_stock_db: lowStockDb,
      failed_cart_db: failedCart,
      updated_item_db: updatedItem,
      cart_db: cart,
      pending_order_db: pending,
      confirm_db_rows: confirmRows,
      accept_db: acceptDb,
      dispatch_db: dispatchDb,
      delivered_db: deliveredDb,
      cancel_db_rows: cancelDbRows,
      delivered_buttons: Array.isArray(delivered.buttons) ? delivered.buttons : [],
    },
    checks: {
      seeded_milk_price_ok: Number(seededMilk.price || 0) === Number(seed.milk_initial_price || 0),
      seeded_milk_stock_ok: Number(seededMilk.stock || 0) === Number(seed.milk_initial_stock || 0),
      seeded_atta_price_ok: Number(seededAtta.price || 0) === Number(seed.atta_initial_price || 0),
      seeded_atta_stock_ok: Number(seededAtta.stock || 0) === Number(seed.atta_initial_stock || 0),
      browse_message_ok: /shop local|pick a quick item/i.test(bodyText(browse)),
      browse_has_quick_pick_rows: hasListRow(browse, 'add_qty__' + String(seed.milk_sku || '') + '__1') || hasListRow(browse, 'add_qty__' + String(seed.atta_sku || '') + '__1'),
      browse_has_shortcuts: hasListRow(browse, 'view_cart') && hasListRow(browse, 'get_promos'),
      empty_place_ok: /cart is empty/i.test(bodyText(emptyPlace)),
      empty_place_buttons_ok: hasButton(emptyPlace, 'start_shopping') && hasButton(emptyPlace, 'get_promos'),
      empty_confirm_ok: /no pending order|no pending bill|there is no pending/i.test(bodyText(emptyConfirm)),
      low_stock_db_ok: Number(lowStockDb.stock || 0) === Number(seed.low_stock || 0),
      insufficient_add_ok: /only\s+1|requested\s+2/i.test(bodyText(insufficientAdd)),
      insufficient_add_left_cart_empty: Number(failedCart.cart_row_count || 0) === 0,
      updated_price_db_ok: Number(updatedItem.price || 0) === Number(seed.updated_milk_price || 0),
      updated_stock_db_ok: Number(updatedItem.stock || 0) === Number(seed.replenished_stock || 0),
      add_buttons_ok: hasButton(add, 'checkout') && hasButton(add, 'view_cart') && hasButton(add, 'add_more'),
      add_uses_updated_price: bodyText(add).includes('₹' + String(seed.expected_line_total)) || bodyText(add).includes('Rs.' + String(seed.expected_line_total)),
      cart_db_price_ok: Number(cart.price_at_addition || 0) === Number(seed.updated_milk_price || 0),
      cart_db_qty_ok: Number(cart.quantity || 0) === Number(seed.order_qty || 0),
      cart_db_line_total_ok: Number(cart.line_total || 0) === Number(seed.expected_line_total || 0),
      view_buttons_ok: hasButton(view, 'checkout') && hasButton(view, 'add_more') && hasButton(view, 'cancel_order'),
      view_cart_total_ok: (() => { const t = Number(seed.expected_line_total || 0).toFixed(2); return bodyText(view).includes(t) || bodyText(view).includes(String(seed.expected_line_total || 0)); })(),
      place_has_confirm_button: hasButton(place, 'confirm_order'),
      pending_status_awaiting_confirmation: String(pending.status || '') === 'awaiting_confirmation',
      pending_unit_price_ok: Number(pending.unit_price || 0) === Number(seed.updated_milk_price || 0),
      pending_quantity_ok: Number(pending.quantity || 0) === Number(seed.order_qty || 0),
      pending_line_total_ok: Number(pending.line_total || 0) === Number(seed.expected_line_total || 0),
      confirm_ok: /order confirmed|order placed/i.test(bodyText(confirm)),
      confirm_pending_status_ok: String(byKind(confirmRows, 'pending').val1 || '') === 'confirmed',
      order_summary_present: Number(byKind(confirmRows, 'order_summary').val1 || 0) >= 1,
      orders_present: Number(byKind(confirmRows, 'orders').val1 || 0) >= 1,
      stock_decremented_after_confirm: Number(byKind(confirmRows, 'inventory_stock').val1 || 0) === Number(seed.replenished_stock || 0) - Number(seed.order_qty || 0),
      active_cart_cleared_after_confirm: Number(byKind(confirmRows, 'active_cart').val1 || 0) === 0,
      track_confirm_status_ok: /order received/i.test(bodyText(trackConfirm)),
      accept_status_db_ok: String(acceptDb.status || '') === 'processing',
      track_accept_status_ok: /packing your order/i.test(bodyText(trackAccept)),
      dispatch_status_db_ok: String(dispatchDb.status || '') === 'dispatched',
      track_dispatch_status_ok: /on the way/i.test(bodyText(trackDispatch)),
      delivered_status_db_ok: String(deliveredDb.status || '') === 'delivered',
      track_delivered_status_ok: /delivered/i.test(bodyText(trackDelivered)),
      delivered_feedback_buttons_ok: hasButtonPrefix(delivered, 'rate_good__') && hasButtonPrefix(delivered, 'rate_bad__'),
      cancel_add_ok: /added|cart|₹|rs\.?/i.test(bodyText(cancelAdd)),
      cancel_place_has_confirm: hasButton(cancelPlace, 'confirm_order'),
      cancel_order_ok: /cancel/i.test(bodyText(cancelOrder)),
      cancel_pending_cleared: Number(byKind(cancelDbRows, 'pending_active').value || 0) === 0,
      cancel_active_cart_cleared: Number(byKind(cancelDbRows, 'active_cart').value || 0) === 0,
    },
  },
}];
